<template><DomainRulesTab :domain-id="domainId" title="Page Rules" summary="Apply edge behavior to matching paths." :fields="fields" :columns="columns" :help-items="helpItems" :list="() => pageRulesApi.list(domainId)" :create="(v) => pageRulesApi.create(domainId, v)" :update="(id, v) => pageRulesApi.update(domainId, id, v)" :remove="(id) => pageRulesApi.remove(domainId, id)" /></template>
<script setup lang="ts">import DomainRulesTab from './DomainRulesTab.vue'; import { pageRulesApi } from '@/lib/api/pageRules'; defineProps<{ domainId:string }>(); const helpItems=[{title:'Pattern examples',body:'Use /* for the whole site, /assets/* for static files, or /checkout/* for one section.'},{title:'Priority',body:'Lower numbers run first. Put narrow rules before broad catch-all rules.'},{title:'Actions JSON',body:'Use valid JSON only. Start with one behavior, save, then layer more changes after testing.'}]; const fields=[{key:'enabled',label:'Enabled',type:'checkbox' as const,default:true,help:'Keep disabled while drafting a risky rule, then enable after review.'},{key:'pattern',label:'Pattern',default:'/*',placeholder:'/*',help:'Match paths, not full URLs. Best practice: use the narrowest path that needs this behavior.'},{key:'priority',label:'Priority',type:'number' as const,default:100,placeholder:'100',help:'Rules with lower priority values are evaluated first.'},{key:'actions',label:'Actions JSON',type:'textarea' as const,default:'{}',placeholder:'{\n  "cache_ttl": 300\n}',help:'Enter a JSON object with the edge actions to apply when the pattern matches.'}]; const columns=[{key:'enabled',label:'Enabled'},{key:'pattern',label:'Pattern'},{key:'priority',label:'Priority'},{key:'actions',label:'Actions'}];</script>
